ee:message.ee:set-payload:
%dw 2.0
output application/xml
---
{
    employees: {
        (payload map (employee, index) -> {
            employee @(id: employee.id): {
                name: employee.name,
                department: employee.department,
                salary: employee.salary
            }
        })
    }
}

%dw 2.0
output application/json
var employees = [
    { name: "Jashwanth", dept: "IT", salary: 75000, active: true },
    { name: "Priya", dept: "HR", salary: 55000, active: false },
    { name: "Rahul", dept: "IT", salary: 90000, active: true },
    { name: "Sneha", dept: "Finance", salary: 65000, active: true }
]
---
{
    activeITEmployees: employees 
        filter (e) -> e.active == true and e.dept == "IT"
        map (e) -> {
            employeeName: e.name,
            annualSalary: e.salary,
            monthlySalary: e.salary / 12,
            department: e.dept
        },
    totalCount: sizeOf(employees filter (e) -> e.active == true and e.dept == "IT")
}
